	goCtx, cancel := context.WithTimeout(context.Background(), maxExecutionTime)
	defer cancel()
	L.SetContext(goCtx)

	// Load and execute the script
	if err := L.DoString(script); err != nil {
		return 0, fmt.Errorf("failed to execute Lua script: %w", err)
	}

	// Get the calculate_final_price function from global scope
	fn := L.GetGlobal("calculate_final_price")
	if fn.Type() != lua.LTFunction {
		return 0, fmt.Errorf("calculate_final_price is not a function or not defined")
	}

	// Convert Go context map to Lua table
	ctxTable := L.NewTable()
	for k, v := range ctx {
		L.SetField(ctxTable, k, lua.LNumber(v))
	}

	// Call the function with the context table
	if err := L.CallByParam(lua.P{
		Fn:      fn,
		NRet:    1,
		Protect: true,
	}, ctxTable); err != nil {
		return 0, fmt.Errorf("failed to call calculate_final_price: %w", err)
	}

	// Get the result from the Lua stack
	result := L.Get(-1)
	L.Pop(1) // Remove the result from the stack

	// Convert result to float64
	if result.Type() != lua.LTNumber {
		return 0, fmt.Errorf("calculate_final_price did not return a number")
	}

	return float64(result.(lua.LNumber)), nil
}

// openSafeLibraries opens only safe Lua standard libraries,
// excluding os, io, debug, and other dangerous modules.
func openSafeLibraries(L *lua.LState) {
	// Open base library but remove dangerous functions afterward
	lua.OpenBase(L)
	// Open math library (safe for pricing calculations)
	lua.OpenMath(L)
	// Open string library (safe)
	lua.OpenString(L)
	// Open table library (safe)
	lua.OpenTable(L)

	// Remove dangerous base functions that could be used for exploitation
	dangerousGlobals := []string{
		"dofile",
		"loadfile",
		"load",
		"loadstring",
		"require",
		"module",
		"rawget",
		"rawset",
		"rawequal",
		"rawlen",
		"collectgarbage",
		"newproxy",
		"getfenv",
		"setfenv",
		"getmetatable",
		"setmetatable",
	}

	for _, name := range dangerousGlobals {
		L.SetGlobal(name, lua.LNil)
	}

	// Ensure os, io, debug, coroutine, channel, package are not available
	modulesToRemove := []string{"os", "io", "debug", "coroutine", "channel", "package"}
	for _, mod := range modulesToRemove {
		L.SetGlobal(mod, lua.LNil)
	}
}

func main() {
